    last_idx = content.rfind(insert_marker)
    if last_idx == -1:
        print("ERROR: Could not find closing ]; in file")
        sys.exit(1)

    # Insert new post before the closing ];
    new_content = content[:last_idx] + ",\n" + NEW_POST + "\n" + content[last_idx:]

